		std::uint_least64_t rlo{__builtin_subcl(static_cast<std::uint_least32_t>(mantissa & 0xFFFFFFFFu), static_cast<std::uint_least32_t>(other.mantissa & 0xFFFFFFFFu), 0u, &carrylo)};
