#elif defined(_M_IX86)
		std::uint_least32_t hileft{data[HI]}, hiright{other.data[HI]};
		if constexpr(!isabsvalue && issignmode && !isfltpmode){// flip the high bit (use an unsigned comparison because of a lack of an overflow flag for the output)
			hileft ^= 0x80000000u;
			hiright ^= 0x80000000u;
		}
		std::uint_least32_t discarded;
		unsigned char carry{_subborrow_u32(_subborrow_u32(0u, data[LO], other.data[LO], &discarded), hileft, hiright, &hileft)};
		return carry;
