#else
				static_assert(64u == CHAR_BIT * sizeof(long), "unexpected size of type long");
				unsigned long carrymid, carry;
				std::uint_least64_t rlo{__builtin_subcl(data[1], other.data[1], 0u, &carrymid)};
				std::uint_least64_t rhi{__builtin_subcl(data[0], other.data[0], carrymid, &carry)};
