		curma += curma;
		curoa += curoa;
		curoa += curma < curmtmpa;
		curmb += curmb;
		curob += curob;
		curob += curmb < curmtmpb;
		curmc += curmc;
		curoc += curoc;
		curoc += curmc < curmtmpc;
