		static_assert(64u == CHAR_BIT * sizeof(long), "unexpected size of type long");
		unsigned long carrysign, checkcarry;
		cur.data[HI] = __builtin_addcl(cur.data[HI], cur.data[HI], 0u, &carrysign);
		cur.data[LO] = __builtin_addcl(cur.data[LO], cur.data[LO], carrysign, &checkcarry);
