		static_cast<void>(carrymid);
#elif defined(_M_IX86)
		unsigned char carrymid{_addcarry_u32(_addcarry_u16(0u, curo, curo, &curo), curmlo, curmlo, &curmlo)};
		static_cast<void>(carrymid);
