		unsigned char checkcarrya{_addcarry_u32(_addcarry_u32(0u, cura.data[HI], cura.data[HI], &cura.data[HI]), cura.data[LO], cura.data[LO], &cura.data[LO])};
		static_cast<void>(checkcarrya);
		unsigned char checkcarryb{_addcarry_u32(_addcarry_u32(0u, curb.data[HI], curb.data[HI], &curb.data[HI]), curb.data[LO], curb.data[LO], &curb.data[LO])};
		static_cast<void>(checkcarryb);
#else
		std::uint_least32_t curhitmpa{cura.data[HI]};
		cura.data[HI] += cura.data[HI];
		cura.data[LO] += cura.data[LO];
		cura.data[LO] += cura.data[HI] < curhitmpa;
		std::uint_least32_t curhitmpb{curb.data[HI]};
		curb.data[HI] += curb.data[HI];
