#elif defined(_M_IX86)
			unsigned char checkcarrya{_addcarry_u32(_addcarry_u32(0u, cura.data[LO], cura.data[LO], &cura.data[LO]), cura.data[HI], cura.data[HI], &cura.data[HI])};
			static_cast<void>(checkcarrya);
