				U curehi0{curehi & (1u << 8) - 1u};
				if constexpr(isabsvalue == isfltpmode && !(isabsvalue && !issignmode)){
					poutput[0].signexponent = static_cast<W>(curehi);
					pbuffer[0].signexponent = static_cast<W>(curehi);
				}
				curehi >>= 8;
				std::uint_least64_t curmhi0{curmhi & (1u << 11) - 1u};
				std::uint_least64_t curmhi1{curmhi >> 11};
				std::uint_least64_t curmhi2{curmhi >> 22};
				std::uint_least64_t curmhi3{curmhi >> 33};
				std::uint_least64_t curmhi4{curmhi >> 44};
