				++offsets[(5u << 11) + (1u << 9) + static_cast<std::size_t>(curehi0)];
				curehi &= ((1u << 8) - 1u) >> static_cast<unsigned>(isabsvalue && issignmode && isfltpmode);
				++offsets[curmhi0];
				curmhi1 &= (1u << 11) - 1u;
				curmhi2 &= (1u << 11) - 1u;
				curmhi3 &= (1u << 11) - 1u;
				curmhi4 &= (1u << 11) - 1u;
