				++offsets[(1u << 8) + (5u << 11) + (1u << 9) + static_cast<std::size_t>(curehi)];
				++offsets[(1u << 11) + static_cast<std::size_t>(curmhi1)];
				++offsets[(2u << 11) + static_cast<std::size_t>(curmhi2)];
				++offsets[(3u << 11) + static_cast<std::size_t>(curmhi3)];
