				std::uint_least64_t curlo6{curlo.data[HI] >> 11};
				std::uint_least64_t curlo7{curlo.data[HI] >> 22};
				std::uint_least64_t curlo8{curlo.data[HI] >> 33};
				std::uint_least64_t curlo9{curlo.data[HI] >> 44};
