				curhi1 &= (1u << 11) - 1u;
				curhi2 &= (1u << 11) - 1u;
				curhi3 &= (1u << 11) - 1u;
				curhi4 &= (1u << 11) - 1u;
				++offsetscompanion[(5u << 11) + static_cast<std::size_t>(curhi.data[LO])];
				++offsetscompanion[(5u << 11) + (1u << 9) + static_cast<std::size_t>(curhi5)];
				curhi6 &= (1u << 11) - 1u;
				curhi7 &= (1u << 11) - 1u;
				curhi8 &= (1u << 11) - 1u;
				curhi9 &= (1u << 11) - 1u;
				if constexpr(isabsvalue && issignmode && isfltpmode) curhi.data[HI] &= (1u << (9 - 1)) - 1u;
				++offsetscompanion[(1u << 11) + static_cast<std::size_t>(curhi1)];
				++offsetscompanion[(2u << 11) + static_cast<std::size_t>(curhi2)];
				++offsetscompanion[(3u << 11) + static_cast<std::size_t>(curhi3)];
				++offsetscompanion[(4u << 11) + static_cast<std::size_t>(curhi4)];
				++offsetscompanion[(6u << 11) + (1u << 9) + static_cast<std::size_t>(curhi6)];
				++offsetscompanion[(7u << 11) + (1u << 9) + static_cast<std::size_t>(curhi7)];
				++offsetscompanion[(8u << 11) + (1u << 9) + static_cast<std::size_t>(curhi8)];
				++offsetscompanion[(9u << 11) + (1u << 9) + static_cast<std::size_t>(curhi9)];
				++offsetscompanion[(10u << 11) + (1u << 9) + static_cast<std::size_t>(curhi.data[HI])];
