			std::uint_least64_t curhi5{curhi.data[HI] & (1u << 11) - 1u};
			std::uint_least64_t curhi6{curhi.data[HI] >> 11};
			std::uint_least64_t curhi7{curhi.data[HI] >> 22};
			std::uint_least64_t curhi8{curhi.data[HI] >> 33};
			std::uint_least64_t curhi9{curhi.data[HI] >> 44};
			if constexpr(isabsvalue == isfltpmode && !(isabsvalue && !issignmode)) pout[0].data[HI] = curhi.data[HI];
