			++offsetscompanion[curhi0];
			curhi1 &= (1u << 11) - 1u;
			curhi2 &= (1u << 11) - 1u;
			curhi3 &= (1u << 11) - 1u;
			curhi4 &= (1u << 11) - 1u;
