			psrchi = pdst;
			std::uintptr_t old{atomiclightbarrier.fetch_add(~std::uintptr_t{})};
			pdst = pdstnext;
			pdstnext = psrchi;
			psrchi += count;
			// skip a step if possible
			runsteps >>= index;
			shifter += index * typeradix<T>;
			poffset += static_cast<std::size_t>(index) << typeradix<T>;
