							cura >>= 8;
							U cur0b{curb & (1u << 8) - 1u};
							curb >>= 8;
							++offsets[cur0a];
							if constexpr(isabsvalue && issignmode && isfltpmode) cura &= (1u << (8 - 1)) - 1u;
							++offsets[cur0b];
							if constexpr(isabsvalue && issignmode && isfltpmode) curb &= (1u << (8 - 1)) - 1u;
							++offsets[(1u << 8) + static_cast<std::size_t>(cura)];
							++offsets[(1u << 8) + static_cast<std::size_t>(curb)];
