#elif 0xFFFFFFFFFFFFFFFFu <= UINTPTR_MAX
			curma += curqa;
			curoa += static_cast<std::uint_least16_t>(curqa);
			curoa += curma < curqa;
			curmb += curqb;
			curob += static_cast<std::uint_least16_t>(curqb);
