	std::size_t largeallocsize{(largepagesize - 1u & -static_cast<std::ptrdiff_t>(allocsize)) + allocsize};// round up to the nearest multiple of largepagesize
	DWORD alloctype{MEM_RESERVE | MEM_COMMIT};
